import{c as e}from"./app.6e7281f6.js";import{_ as a}from"./plugin-vue_export-helper.21dcd24c.js";const t={},r=e('<p>\u77E5\u6211\u8005\u8C13\u6211\u5FC3\u5FE7\uFF0C\u4E0D\u77E5\u6211\u8005\u8C13\u6211\u4F55\u6C42</p><h2 id="\u5F15\u8A00" tabindex="-1"><a class="header-anchor" href="#\u5F15\u8A00" aria-hidden="true">#</a> \u5F15\u8A00</h2><p>\u5982\u679C\u4F60\u6B63\u5728\u4F7F\u7528Vue.js\uFF0C\u90A3\u4E48\u6211\u60F3\u4F60\u4E00\u5B9A\u5BF9Vue\u5355\u6587\u4EF6\u7EC4\u4EF6\uFF08SFC\uFF09\u4E0D\u964C\u751F\uFF0C\u5B83\u662FVue.js\u6846\u67B6\u63D0\u4F9B\u7684\u4E00\u79CD\u6587\u4EF6\u683C\u5F0F\uFF0C\u5728\u7EDD\u5927\u591A\u6570\u5E94\u7528\u573A\u666F\u4E2D\u90FD\u662FVue.js\u5B98\u65B9\u63A8\u8350\u7684\u9879\u76EE\u7EC4\u7EC7\u5F62\u5F0F\uFF0C\u672C\u6587\u5C31\u8BA9\u6211\u4EEC\u4EE5\u5355\u6587\u4EF6\u7EC4\u4EF6\u4E3A\u6E90\u53BB\u56DE\u6EAF\u4E00\u4E0B\u7EC4\u4EF6\u7684\u672C\u8D28\u3002</p><h2 id="\u4EC0\u4E48\u662F\u7EC4\u4EF6" tabindex="-1"><a class="header-anchor" href="#\u4EC0\u4E48\u662F\u7EC4\u4EF6" aria-hidden="true">#</a> \u4EC0\u4E48\u662F\u7EC4\u4EF6</h2><p>\u5728Vue.js\u4E2D\uFF0C\u5355\u6587\u4EF6\u7EC4\u4EF6\u53EF\u4EE5\u8BA4\u4E3A\u662F\u5BF9Vue.js\u7EC4\u4EF6\u7684\u8FDB\u4E00\u6B65\u5C01\u88C5\uFF0C\u5B83\u6742\u7CC5\u4E86<code>HTML</code>\u3001<code>JavaScript</code>\u4EE5\u53CA<code>CSS</code>\u4E09\u79CD\u5143\u7D20\u7684\u7279\u70B9\uFF0C\u4EE5<code>&lt;template&gt;</code>\u3001<code>&lt;script&gt;</code>\u53CA<code>&lt;style&gt;</code>\u4E09\u5927\u5757\u5C06\u4E0E\u4E00\u4E2A\u7EC4\u4EF6\u76F8\u5173\u7684\u89C6\u56FE\u3001\u903B\u8F91\u4EE5\u53CA\u6837\u5F0F\u6574\u5408\u5230\u4E86\u4E00\u4E2A\u57FA\u672C\u7684\u7279\u6B8A\u6587\u4EF6\u5355\u4F4D\u4E4B\u4E2D\uFF0C\u4E0B\u9762\u662F\u4E00\u4E2A\u5355\u6587\u4EF6\u7EC4\u4EF6\u7684\u793A\u4F8B\uFF1A</p><p><img src="https://p3-juejin.byteimg.com/tos-cn-i-k3u1fbpfcp/6a48dba2de3542db9de4fb22695717d3~tplv-k3u1fbpfcp-watermark.image?" alt="carbon (31).png"></p><p>\u4F60\u53EF\u80FD\u4E0D\u77E5\u9053\uFF0C\u5176\u5B9E\u5728Vue.js\u5185\u90E8\uFF0C\u4E0A\u8FF0\u5355\u6587\u4EF6\u7EC4\u4EF6\u4F1A\u7ECF\u7531<a href="https://github.com/vuejs/core/tree/main/packages/compiler-sfc" target="_blank" rel="noopener noreferrer">@vue/compiler-sfc</a>\u7F16\u8BD1\u4E3A\u6807\u51C6\u7684JavaScript\u548CCSS\uFF0C\u7F16\u8BD1\u540E\u7684JavaScript\u6587\u4EF6\u53EF\u80FD\u5982\u4E0B(<strong>\u4E2A\u4EBA\u63A8\u6D4B\uFF0C\u5982\u9519\uFF0C\u70E6\u8BF7\u6307\u6B63</strong>)\uFF1A</p><p><img src="https://p9-juejin.byteimg.com/tos-cn-i-k3u1fbpfcp/62854beb38164a328515c160fa99a270~tplv-k3u1fbpfcp-watermark.image?" alt="carbon (32).png"></p><p>\u8FD9\u4E2A\u51FD\u6570\u7684\u8FD4\u56DE\u503C\u662F\u4E0D\u662F\u5F88\u719F\u6089\uFF1F\u8FD9\u5C31\u662F\u4E00\u4E2A\u865A\u62DFDOM\u5BF9\u8C61\uFF0C\u5728\u8FD9\u91CC\u4F60\u5C31\u53EF\u4EE5\u79F0\u8FD9\u4E2A\u51FD\u6570\u4E3A<strong>\u7EC4\u4EF6</strong>\uFF01\uFF08\u5982\u679C\u4F60\u5BF9\u865A\u62DFDOM\u8FD8\u4E0D\u719F\u6089\uFF0C\u8BF7\u53C2\u9605\u6211\u7684\u8FD9\u7BC7\u7B14\u8BB0-<a href="https://juejin.cn/post/7067905116745138213" target="_blank" rel="noopener noreferrer">\u4E3A\u4EC0\u4E48Vue.js\u4E2D\u8981\u91C7\u7528\u865A\u62DFDOM</a>\uFF09</p><p>\u5BF9\uFF0C\u8FD9\u5C31\u662F\u7EC4\u4EF6\uFF0C\u7EC4\u4EF6\u7684\u5B9E\u8D28\u5176\u5B9E\u5C31\u662F<strong>\u5BF9\u4E00\u7EC4DOM\u5143\u7D20\u7684\u5C01\u88C5</strong>\u3002\u73B0\u5728\uFF0C\u8BA9\u6211\u4EEC\u81EA\u5DF1\u5B9A\u4E49\u4E00\u4E2A\u7EC4\u4EF6\u6765\u719F\u6089\u5DE9\u56FA\u4E00\u4E0B\uFF1A</p><p><img src="https://p9-juejin.byteimg.com/tos-cn-i-k3u1fbpfcp/4cc85294402846a2a229529455dfe7dc~tplv-k3u1fbpfcp-watermark.image?" alt="carbon (33).png"></p><p>\u7EFC\u4E0A\uFF0C\u6211\u4EEC\u53EF\u4EE5\u5B9A\u4E49\u4E00\u4E2A\u51FD\u6570\u6765\u4EE3\u8868\u7EC4\u4EF6\uFF0C\u800C\u51FD\u6570\u7684\u8FD4\u56DE\u503C\u5C31\u4EE3\u8868\u7EC4\u4EF6\u8981\u6E32\u67D3\u7684\u5185\u5BB9\u3002</p><h2 id="\u7EC4\u4EF6\u7684\u6E32\u67D3" tabindex="-1"><a class="header-anchor" href="#\u7EC4\u4EF6\u7684\u6E32\u67D3" aria-hidden="true">#</a> \u7EC4\u4EF6\u7684\u6E32\u67D3</h2><p>\u4ECE\u4E0A\u6587\u53EF\u4EE5\u770B\u5230\uFF0C\u7EC4\u4EF6\u7684\u8FD4\u56DE\u503C\u5C31\u662F\u865A\u62DFDOM\u5BF9\u8C61\uFF0C\u5B83\u4EE3\u8868\u7740\u7EC4\u4EF6\u60F3\u8981\u6E32\u67D3\u7684\u5185\u5BB9\u3002\u90A3\u4E48\u5728Vue.js\u4E2D\u7EC4\u4EF6\u662F\u5982\u4F55\u6E32\u67D3\u7684\u5462\uFF1F\uFF08\u5982\u679C\u4F60\u5BF9Vue.js\u4E2D\u865A\u62DFDOM\u7684\u6E32\u67D3\u539F\u7406\u8FD8\u4E0D\u751A\u4E86\u89E3\uFF0C\u53EF\u4EE5\u53C2\u9605\u4E00\u4E0B\u6211\u8FD9\u7BC7\u7B14\u8BB0-<a href="https://juejin.cn/post/7068140506529660935" target="_blank" rel="noopener noreferrer">\u6D45\u6790Vue.js\u7684\u8FD0\u884C\u65F6\u7F16\u8BD1</a>\uFF09</p><p>\u4E3A\u4E86\u66F4\u52A0\u76F4\u89C2\u5730\u63CF\u8FF0\uFF0C\u6211\u4EEC\u5148\u7528\u4E00\u4E2A\u865A\u62DFDOM\u5BF9\u8C61\u4E2D\u7684<code>tag</code>\u6807\u7B7E\u6765\u50A8\u5B58\u7EC4\u4EF6\u51FD\u6570\uFF1A</p><p><img src="https://p3-juejin.byteimg.com/tos-cn-i-k3u1fbpfcp/e60c73b585554f86a7eff5a8953cd260~tplv-k3u1fbpfcp-watermark.image?" alt="carbon (34).png"></p><p>\u4F60\u53EF\u80FD\u5BF9\u8FD9\u79CD\u63CF\u8FF0\u4E0D\u662F\u592A\u719F\u6089\uFF0C\u56E0\u4E3A\u4EE5\u524D\u63A5\u89E6\u5230\u7684\u865A\u62DFDOM\u53EF\u80FD\u90FD\u662F\u7528<code>tag</code>\u5C5E\u6027\u503C\u6765\u63CF\u8FF0<code>HTML</code>\u6807\u7B7E\uFF0C\u5176\u5B9E\uFF0C\u53EA\u8981\u5F97\u5230\u6E32\u67D3\u5668\u7684\u652F\u6301\uFF0C<code>tag: MyComponent</code>\u662F\u5B8C\u5168\u7B26\u5408\u8BED\u6CD5\u7684\u3002\u6B64\u65F6\uFF0C\u8D1F\u8D23\u628A\u865A\u62DFDOM\u6E32\u67D3\u4E3A\u771F\u5B9EDOM\u7684\u6E32\u67D3\u5668\u4EE3\u7801\u5B9E\u73B0\u539F\u7406\u5982\u4E0B\uFF1A</p><p><img src="https://p9-juejin.byteimg.com/tos-cn-i-k3u1fbpfcp/abcd4a6cf4f94109bd5a8179d87aa7f1~tplv-k3u1fbpfcp-watermark.image?" alt="carbon (36).png"></p><h2 id="\u7EC4\u4EF6\u7684\u62D3\u5C55" tabindex="-1"><a class="header-anchor" href="#\u7EC4\u4EF6\u7684\u62D3\u5C55" aria-hidden="true">#</a> \u7EC4\u4EF6\u7684\u62D3\u5C55</h2><p>\u8FD8\u8BB0\u5F97\u7EC4\u4EF6\u7684\u5B9E\u8D28\u662F\u4EC0\u4E48\u5417\uFF1F\u7EC4\u4EF6\u7684\u5B9E\u8D28\u5C31\u662F<strong>\u5BF9\u4E00\u7EC4DOM\u5143\u7D20\u7684\u5C01\u88C5</strong>\uFF01\u90A3\u4E48\u95EE\u9898\u6765\u4E86\uFF0C\u5728\u4E0A\u6587\u4E2D\u4E00\u76F4\u90FD\u662F\u7528\u4E00\u4E2A\u51FD\u6570\u6765\u81EA\u5B9A\u4E49\u7EC4\u4EF6\uFF0C\u4F46\u662F\u7EC4\u4EF6\u7684\u8868\u793A\u65B9\u5F0F\u53EA\u80FD\u662F\u51FD\u6570\u5417\uFF1F\u4E0D\u4E0D\u4E0D\uFF0C\u5F53\u7136\u4E0D\u662F\uFF0C\u4F60\u5B8C\u5168\u53EF\u4EE5\u4F7F\u7528\u4E00\u4E2AJavaScript\u5BF9\u8C61\u6765\u81EA\u5B9A\u4E49\u7EC4\u4EF6\uFF0C\u5982\u4E0B\uFF1A</p><p><img src="https://p6-juejin.byteimg.com/tos-cn-i-k3u1fbpfcp/781713dde2f640b2ad10bb7f8b667353~tplv-k3u1fbpfcp-watermark.image?" alt="carbon (37).png"></p><p>\u5728\u8FD9\u4E2A<code>MyComponent</code>\u5BF9\u8C61\u4E2D\uFF0C\u5C5E\u6027<code>render</code>\u51FD\u6570\u7684\u8FD4\u56DE\u503C\u662F\u4E00\u4E2A\u865A\u62DFDOM\u5BF9\u8C61\uFF0C\u4EE3\u8868\u7740\u6B64\u7EC4\u4EF6\u7684\u6E32\u67D3\u5185\u5BB9\u3002\u76F8\u5E94\u7684\uFF0C\u4E3A\u4E86\u80FD\u591F\u6B63\u5E38\u4F7F\u7528\u5BF9\u8C61\u7EC4\u4EF6\u6E32\u67D3DOM\uFF0C\u9700\u8981\u5BF9\u4E0A\u8FF0\u4E3E\u4F8B\u7684\u6E32\u67D3\u5668\u505A\u76F8\u5E94\u7684\u4FEE\u6539\u9002\u914D\uFF0C\u4FEE\u6539\u5982\u4E0B\uFF1A</p><p><img src="https://p3-juejin.byteimg.com/tos-cn-i-k3u1fbpfcp/11c1dccc77454c1c928da86aebf2cad2~tplv-k3u1fbpfcp-watermark.image?" alt="carbon (38).png"></p><p>\u5728\u4E0A\u8FF0\u4EE3\u7801\u4E2D\uFF0C<code>vnode.tag</code>\u5C31\u662F\u8868\u8FBE\u7EC4\u4EF6\u7684\u5BF9\u8C61\u3002\u5176\u5B9E\u5728Vue.js\u4E2D\u4E5F\u6709\u4F7F\u7528\u5BF9\u8C61\u7ED3\u6784\u6765\u8868\u8FBE\u7684\u7EC4\u4EF6\uFF0C\u5373\u6709\u72B6\u6001\u7EC4\u4EF6\u3002</p><h2 id="\u53C2\u8003\u8D44\u6599" tabindex="-1"><a class="header-anchor" href="#\u53C2\u8003\u8D44\u6599" aria-hidden="true">#</a> \u53C2\u8003\u8D44\u6599</h2><ul><li><a href="https://vuejs.org/guide/scaling-up/sfc.html" target="_blank" rel="noopener noreferrer">Vue.js\u5B98\u7F51-sfc</a></li><li><a href="https://juejin.cn/post/7020683936346931230" target="_blank" rel="noopener noreferrer">\u6398\u91D1-\u75AF\u72C2\u5E73\u5934\u54E5-\u7EC4\u4EF6\u7684\u672C\u8D28</a></li></ul>',26);function p(c,o){return r}var s=a(t,[["render",p]]);export{s as default};
